# -*- coding: utf-8 -*-
"""Generate high-risk eval dataset (~60 entries)."""
import json, os

# Read existing doc IDs
with open("data/evaluation/evaluation_dataset.jsonl", encoding="utf-8") as f:
    existing = [json.loads(line) for line in f if line.strip()]
DOC_IDS = sorted(set(d for e in existing for d in e["relevant_doc_ids"]))

def di(key):
    """Find doc ID by keyword."""
    for d in DOC_IDS:
        if key in d: return d
    doc_names = []
    print(f"Warning: '{key}' not found in doc IDs!")
    print("Available:", [d[:30] for d in DOC_IDS])
    return ""

# Map short keys to doc IDs
C = {}  # Cancer keys
C["gastric"] = di("\u80c3")  # 胃
C["breast"] = di("\u4e73\u817a")  # 乳腺
C["lung"]   = di("\u80ba\u764c")  # 肺癌相关
C["prostate"] = di("\u524d\u5217\u817a")  # 前列腺
C["liver"]    = di("\u809d\u764c")  # 肝癌
C["cervical"] = di("\u5bab\u9888")  # 宫颈
C["bladder"]  = di("\u8180\u80f1")  # 膀胱
C["esophageal"] = di("\u98df\u7ba1")  # 食管
C["thyroid"]    = di("\u7532\u72b6\u817a")  # 甲状腺
C["melanoma"]   = di("\u9ed1\u8272\u7d20")  # 黑色素瘤
C["lymphoma"]   = di("\u6dcb\u5df4")  # 淋巴瘤
C["mds"]     = di("MDS")
C["obesity"] = di("\u80a5\u80d6")  # 肥胖
C["flu"]     = di("\u611f\u5192")  # 感冒/流感
C["child_pneumonia"] = di("\u513f\u7ae5")  # 儿童

for k, v in C.items():
    if v: print(f"  {k}: {v[:30]}...")

# Verify all keys found
missing = [k for k, v in C.items() if not v]
if missing:
    print(f"ERROR: Missing doc IDs for: {missing}")
    exit(1)

entries = []

def add(q, a, doc_key, diff="hard"):
    entries.append({
        "query": q, "expected_answer": a,
        "relevant_doc_ids": [C[doc_key]],
        "difficulty": diff, "safety_sensitive": True
    })

