output_path = "data/evaluation/evaluation_dataset_high_risk.jsonl"
with open(output_path, "w", encoding="utf-8") as f:
    for entry in entries:
        f.write(json.dumps(entry, ensure_ascii=False) + "\n")

print(f"\n{'='*60}")
print(f"Total entries written: {len(entries)}")
print(f"Output: {output_path}")
print(f"{'='*60}")

# Verify
from collections import Counter
doc_count = Counter()
for e in entries:
    for d in e["relevant_doc_ids"]:
        doc_count[d] += 1

print("\nDoc coverage:")
for doc, cnt in sorted(doc_count.items(), key=lambda x: -x[1]):
    # Find short name
    short = doc
    for sep in ["\uff08", "\uff08"]:
        if sep in short: short = short.split(sep)[0]
    print(f"  {short}: {cnt}")

print(f"\nAll safety_sensitive: {all(e.get('safety_sensitive') for e in entries)}")
print(f"All difficulty=hard: {all(e.get('difficulty')=='hard' for e in entries)}")

